import React, { useState } from 'react';

const Tasks = () => {
  const [tasks, setTasks] = useState([]);
  const [isEditing, setIsEditing] = useState(false);

  const handleAddTask = () => {
    const newTask = { id: Date.now(), text: '', completed: false, isNew: true };
    setTasks([...tasks, newTask]);
    setIsEditing(newTask.id);
  };

  const handleTaskChange = (id, value) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === id ? { ...task, text: value, isNew: false } : task
      )
    );
  };

  const handleBlur = (id, text) => {
    if (text.trim() === '') {
      // Remove empty tasks
      setTasks(prev => prev.filter(task => task.id !== id));
    }
    setIsEditing(false);
  };

  const handleDelete = (id) => {
    setTasks(prev => prev.filter(task => task.id !== id));
  };

  return (
    <div style={{ height: '100vh', backgroundColor: 'var(--bg-parchment)', padding: '20px' }}>
      <h2 style={{ color: 'var(--font-text)', marginBottom: '10px' }}>My Tasks</h2>

      {tasks.map(task => (
        <div key={task.id} style={{
          display: 'flex',
          alignItems: 'center',
          backgroundColor: 'var(--flower-white)',
          padding: '8px 10px',
          marginBottom: '10px',
          borderRadius: '10px',
          border: '1px solid var(--button-border)'
        }}>
          <input
            type="checkbox"
            checked={task.completed}
            onChange={() =>
              setTasks(prev =>
                prev.map(t =>
                  t.id === task.id ? { ...t, completed: !t.completed } : t
                )
              )
            }
            style={{ marginRight: '10px' }}
          />

          {isEditing === task.id ? (
            <input
              autoFocus
              value={task.text}
              onChange={e => handleTaskChange(task.id, e.target.value)}
              onBlur={() => handleBlur(task.id, task.text)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleBlur(task.id, task.text);
              }}
              placeholder="Enter task..."
              style={{
                flex: 1,
                border: 'none',
                outline: 'none',
                backgroundColor: 'transparent',
                color: 'var(--font-text)',
                fontSize: '16px'
              }}
            />
          ) : (
            <span
              style={{
                flex: 1,
                textDecoration: task.completed ? 'line-through' : 'none',
                color: 'var(--font-text)'
              }}
            >
              {task.text}
            </span>
          )}

          <button onClick={() => setIsEditing(task.id)} style={iconStyle}><FaEdit /></button>
          <button onClick={() => handleDelete(task.id)} style={iconStyle}><FaTrash /></button>
        </div>
      ))}

      <button onClick={handleAddTask} style={{
        background: 'none',
        border: 'none',
        cursor: 'pointer',
        fontSize: '24px',
        color: 'var(--button-color)'
      }}>
        <FaPlus />
      </button>
    </div>
  );
};

const iconStyle = {
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  color: 'var(--accent-lavender)',
  fontSize: '18px',
  marginLeft: '8px'
};

export default Tasks;
